// Apply colors button
const applyColorsButton = document.getElementById('applyColorsButton');
if (!applyColorsButton.hasEventListener) {
  applyColorsButton.addEventListener('click', function(event) {
    event.preventDefault(); // Prevent form submission

    // Retrieve selected color values
    const primaryColor = document.getElementById('primaryColor').value;
    const secondaryColor = document.getElementById('secondaryColor').value;
    const accentColor = document.getElementById('accentColor').value;
    const dangerColor = document.getElementById('dangerColor').value;
    const backgroundColor = document.getElementById('backgroundColor').value;
    const textColor = document.getElementById('textColor').value;
    const headerColor = document.getElementById('headerColor').value;
    const borderRadius = document.getElementById('borderRadius').value;

    // Update CSS variables with selected colors and border radius
    document.documentElement.style.setProperty('--color-primary', primaryColor);
    document.documentElement.style.setProperty('--color-secondary', secondaryColor);
    document.documentElement.style.setProperty('--color-accent', accentColor);
    document.documentElement.style.setProperty('--color-danger', dangerColor);
    document.documentElement.style.setProperty('--color-bg', backgroundColor);
    document.documentElement.style.setProperty('--color-text', textColor);
    document.querySelector('.header').style.setProperty('--header-bg-color', headerColor);
    document.documentElement.style.setProperty('--border-radius', borderRadius + 'px');

    // Display confirmation message as a pop-up alert
    window.alert('Colors applied');
  });
  applyColorsButton.hasEventListener = true;
}

// Save to browser button
const saveToBrowserButton = document.getElementById('saveToBrowserButton');
if (!saveToBrowserButton.hasEventListener) {
  saveToBrowserButton.addEventListener('click', function(event) {
    event.preventDefault(); // Prevent form submission

    // Retrieve selected color values
    const primaryColor = document.getElementById('primaryColor').value;
    const secondaryColor = document.getElementById('secondaryColor').value;
    const accentColor = document.getElementById('accentColor').value;
    const dangerColor = document.getElementById('dangerColor').value;
    const backgroundColor = document.getElementById('backgroundColor').value;
    const textColor = document.getElementById('textColor').value;
    const headerColor = document.getElementById('headerColor').value;
    const borderRadius = document.getElementById('borderRadius').value;

    // Save color values and border radius to browser storage (e.g., localStorage or sessionStorage)
    // Replace 'yourKey' with a unique key to store the values
    localStorage.setItem('yourKey-primaryColor', primaryColor);
    localStorage.setItem('yourKey-secondaryColor', secondaryColor);
    localStorage.setItem('yourKey-accentColor', accentColor);
    localStorage.setItem('yourKey-dangerColor', dangerColor);
    localStorage.setItem('yourKey-backgroundColor', backgroundColor);
    localStorage.setItem('yourKey-textColor', textColor);
    localStorage.setItem('yourKey-headerColor', headerColor);
    localStorage.setItem('yourKey-borderRadius', borderRadius);

    // Update the CSS variable values in the <div> block
    document.getElementById('primaryColorValue').textContent = primaryColor;
    document.getElementById('secondaryColorValue').textContent = secondaryColor;
    document.getElementById('accentColorValue').textContent = accentColor;
    document.getElementById('dangerColorValue').textContent = dangerColor;
    document.getElementById('backgroundColorValue').textContent = backgroundColor;
    document.getElementById('textColorValue').textContent = textColor;
    document.getElementById('headerColorValue').textContent = headerColor;
    document.getElementById('borderRadiusValue').textContent = borderRadius + 'px';

    // Update the color blocks in the <div> block
    document.getElementById('primaryColorBlock').style.backgroundColor = primaryColor;
    document.getElementById('secondaryColorBlock').style.backgroundColor = secondaryColor;
    document.getElementById('accentColorBlock').style.backgroundColor = accentColor;
    document.getElementById('dangerColorBlock').style.backgroundColor = dangerColor;
    document.getElementById('backgroundColorBlock').style.backgroundColor = backgroundColor;
    document.getElementById('textColorBlock').style.backgroundColor = textColor;
    document.getElementById('headerColorBlock').style.backgroundColor = headerColor;
    document.getElementById('borderRadiusBlock').style.borderRadius = borderRadius + 'px';

    // Display confirmation message as a pop-up alert
    window.alert('Colors saved to browser');
  });
  saveToBrowserButton.hasEventListener = true;
}

